toolArgs.file_text:
.step-indicator {
    gap: 0;
}

.step-item {
    position: relative;
    min-width: 40px;
    flex: 0 1 auto !important;
}

.step-connector {
    flex: 1 1 auto !important;
    padding: 0 4px;
}

.step-connector hr {
    border-top: 2px solid #dee2e6;
    margin: 0;
    opacity: 1;
}

.step-connector hr.completed {
    border-color: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.875rem;
}

.step-label {
    display: block;
    font-size: 0.75rem;
    margin-top: 4px;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: white;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: white;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #6c757d;
}

.step-item.future .step-label {
    color: #adb5bd;
}

.step-btn {
    color: inherit;
    border: none;
    background: none;
}

.step-btn:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

