toolArgs.file_text:
@* Step 1: Personal information form *@

<h4 class="mb-4">Personal Information</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Info.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")" @bind="Info.Email" @bind:event="oninput" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">Please enter a valid email address.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Info.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Info.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Info { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? errorMessage;
    private bool emailInvalid;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;
        emailInvalid = false;

        if (string.IsNullOrWhiteSpace(Info.FullName) ||
            string.IsNullOrWhiteSpace(Info.Email) ||
            string.IsNullOrWhiteSpace(Info.Phone) ||
            string.IsNullOrWhiteSpace(Info.Address))
        {
            errorMessage = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(Info.Email);
            if (!valid)
            {
                emailInvalid = true;
                errorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

